// Pegando os valores do input do n8n
const inputData = $input.first().json;
const startDateTime = inputData.start.dateTime;
const endDateTime = inputData.end.dateTime;
// --- DADOS ADICIONAIS ---
const linkCall = inputData.hangoutLink || "Link não disponível"; // Pega o link da call
const assunto = inputData.summary || "Assunto não disponível";    // Pega o assunto do evento

// --- LÓGICA DE DATA E HORA COM CORREÇÃO DE FUSO (SEM ALTERAÇÃO) ---

// Função auxiliar para parsear a string de data, tratando os números como se fossem UTC
function parseISOAsUTC(isoString) {
  if (!isoString) return new Date(NaN);
  const cleanISO = isoString.substring(0, 19);
  return new Date(cleanISO + 'Z');
}

// Criando objetos Date usando nossa função segura
const dataInicio = parseISOAsUTC(startDateTime);
const dataFim = parseISOAsUTC(endDateTime);

// Array com os dias da semana em português
const diasDaSemana = ["domingo", "segunda-feira", "terça-feira", "quarta-feira", "quinta-feira", "sexta-feira", "sábado"];

// Verificação para garantir que a data é válida antes de formatar
if (isNaN(dataInicio.getTime())) {
  return [{ json: { output: "Erro: Data de início inválida." } }];
}

// Extraindo e formatando usando os métodos getUTC* para ler os valores corretos
const diaSemana = diasDaSemana[dataInicio.getUTCDay()];
const dia = String(dataInicio.getUTCDate()).padStart(2, '0');
const mes = String(dataInicio.getUTCMonth() + 1).padStart(2, '0');
const ano = dataInicio.getUTCFullYear();
const dataFormatada = `${diaSemana}, ${dia}/${mes}/${ano}`;

const horaInicio = String(dataInicio.getUTCHours()).padStart(2, '0');
const minutoInicio = String(dataInicio.getUTCMinutes()).padStart(2, '0');
const horarioInicio = `${horaInicio}:${minutoInicio}`;

const horaFim = String(dataFim.getUTCHours()).padStart(2, '0');
const minutoFim = String(dataFim.getUTCMinutes()).padStart(2, '0');
const horarioFim = `${horaFim}:${minutoFim}`;

// --- MONTAGEM DA SAÍDA FINAL ---

// Monta a string de horário completa, incluindo o fuso horário para clareza
const horarioDataCompleto = `${dataFormatada} da ${horarioInicio} às ${horarioFim}`;

// Monta a mensagem de saída final no formato desejado
const output = `
Horário e Data: ${horarioDataCompleto}

Link da Call: ${linkCall}

Assunto: ${assunto}
`;

// Retorna o JSON com a mensagem final pronta
return [{ json: { output } }];

// --- FUNÇÕES AUXILIARES ---

// Função "inteligente" que lida com os formatos DD/MM/YYYY e YYYY-MM-DD
function parseDataInteligente(dataString) {
  if (!dataString || typeof dataString !== 'string') return new Date(NaN);

  let dia, mes, ano, horas, minutos, segundos;
  const dataComEspaco = dataString.replace('T', ' ');
  const [datePart, timePart] = dataComEspaco.split(' ')[0] + ' ' + dataComEspaco.split(' ')[1].split('-')[0];

  const [data, hora] = dataComEspaco.split(' ');
  const [dateOnly] = data.split('T');

  if (dateOnly.includes('/')) {
    [dia, mes, ano] = dateOnly.split('/').map(Number);
  } else {
    [ano, mes, dia] = dateOnly.split('-').map(Number);
  }

  [horas, minutos, segundos] = hora.split(':').map(Number);
  return new Date(ano, mes - 1, dia, horas, minutos, segundos || 0);
}

// Função que formata a data para o padrão Google (ISO 8601), corrigindo o fuso
function formatToGoogleStandard(data) {
  if (isNaN(data.getTime())) return null;

  const ano = data.getFullYear();
  const mes = String(data.getMonth() + 1).padStart(2, '0');
  const dia = String(data.getDate()).padStart(2, '0');
  const horas = String(data.getHours()).padStart(2, '0');
  const minutos = String(data.getMinutes()).padStart(2, '0');
  const segundos = "00";

  return `${ano}-${mes}-${dia}T${horas}:${minutos}:${segundos}-03:00`;
}

// --- DADOS DO NOVO AGENDAMENTO (pegos uma única vez) ---

const dadosAgendamento = $('DadosAgendamento').first().json;
const novoHorarioInicioStr = dadosAgendamento.horarioAgendamento;
const tempoReuniaoMinutos = dadosAgendamento.tempoReuniao;

// Parseia e calcula as datas para o NOVO agendamento
const dataInicioNovo = parseDataInteligente(novoHorarioInicioStr);
const dataFimNovo = new Date(dataInicioNovo);
dataFimNovo.setMinutes(dataFimNovo.getMinutes() + tempoReuniaoMinutos);

// Formata as datas do NOVO agendamento
const inicioNovoAgendamento = formatToGoogleStandard(dataInicioNovo);
const fimNovoAgendamento = formatToGoogleStandard(dataFimNovo);


// --- PROCESSAMENTO DOS EVENTOS ANTIGOS (DENTRO DO LOOP) ---

const results = [];

for (const item of items) {
  try {
    // Verifica se os valores do evento ANTIGO existem
    if (!item.json.horario_ocupado_start || !item.json.horario_ocupado_end) {
      throw new Error("Horário do evento antigo não disponível");
    }

    // Pega os dados do evento ANTIGO
    const startDateTimeAntigo = item.json.horario_ocupado_start;
    const endDateTimeAntigo = item.json.horario_ocupado_end;
    const eventId = item.json.id_evento_calendar || "ID não disponível";
    const eventStatus = item.json.id_evento_calendar_status || "Status não disponível";

    // Formata as datas do evento ANTIGO (sem alteração na lógica)
    const inicioAntigoFormatado = formatToGoogleStandard(parseDataInteligente(startDateTimeAntigo));
    const fimAntigoFormatado = formatToGoogleStandard(parseDataInteligente(endDateTimeAntigo));

    if (!inicioAntigoFormatado || !fimAntigoFormatado) {
      throw new Error("Falha ao formatar data do evento antigo.");
    }

    const emailAttendList = typeof item.json.email_attend === "string" 
      ? JSON.parse(item.json.email_attend) 
      : item.json.email_attend;
    const email = emailAttendList?.[0]?.email || "E-mail não disponível";

    // Adiciona TODOS os dados (antigos e novos) ao resultado final
    results.push({
      json: {
        email: email,
        horario_agendado_inicio: inicioAntigoFormatado, // Horário antigo
        horario_agendado_fim: fimAntigoFormatado,       // Horário antigo
        id_evento: eventId,
        status_evento: eventStatus,
        // --- NOVAS SAÍDAS ADICIONADAS AQUI ---
        inicioNovoAgendamento: inicioNovoAgendamento, // Horário novo
        fimNovoAgendamento: fimNovoAgendamento,     // Horário novo
      }
    });

  } catch (error) {
    results.push({
      json: {
        // ... bloco de erro sem alteração, mas adicionando os campos novos como nulos
        email: "E-mail não disponível",
        horario_agendado_inicio: "Data inválida",
        horario_agendado_fim: "Data inválida",
        id_evento: "ID não disponível",
        status_evento: "Status não disponível",
        inicioNovoAgendamento: null,
        fimNovoAgendamento: null,
      }
    });
  }
}

return results;

// Pegando os valores do input do n8n
const inputData = $input.first().json;
const startDateTime = inputData.start.dateTime; // Ex: "2025-07-15T18:00:00-03:00"
const endDateTime = inputData.end.dateTime;
const linkCall = inputData.hangoutLink || "Link não disponível"; // Pega o link da call
const assunto = inputData.summary || "Assunto não disponível";    // Pega o assunto do evento

// --- LÓGICA DE DATA E HORA COM CORREÇÃO DE FUSO ---

// Função auxiliar para interpretar a string de data como UTC, ignorando a conversão do servidor
function parseISOAsUTC(isoString) {
  if (!isoString) return new Date(NaN);
  // Pega apenas a parte "YYYY-MM-DDTHH:MM:SS" e adiciona 'Z' para tratar como UTC
  const cleanISO = isoString.substring(0, 19);
  return new Date(cleanISO + 'Z');
}

// Criando objetos Date usando nossa função segura
const dataInicio = parseISOAsUTC(startDateTime);
const dataFim = parseISOAsUTC(endDateTime);

// Array com os dias da semana em português
const diasDaSemana = ["domingo", "segunda-feira", "terça-feira", "quarta-feira", "quinta-feira", "sexta-feira", "sábado"];

// Verificação para garantir que a data é válida antes de formatar
if (isNaN(dataInicio.getTime())) {
  return [{ json: { output: "Erro: Data de início inválida." } }];
}

// Extraindo e formatando usando os métodos getUTC* para pegar os valores corretos
const diaSemana = diasDaSemana[dataInicio.getUTCDay()];
const dia = String(dataInicio.getUTCDate()).padStart(2, '0');
const mes = String(dataInicio.getUTCMonth() + 1).padStart(2, '0');
const ano = dataInicio.getUTCFullYear();
const dataFormatada = `${diaSemana}, ${dia}/${mes}/${ano}`;

const horaInicio = String(dataInicio.getUTCHours()).padStart(2, '0');
const minutoInicio = String(dataInicio.getUTCMinutes()).padStart(2, '0');
const horarioInicio = `${horaInicio}:${minutoInicio}`;

const horaFim = String(dataFim.getUTCHours()).padStart(2, '0');
const minutoFim = String(dataFim.getUTCMinutes()).padStart(2, '0');
const horarioFim = `${horaFim}:${minutoFim}`;

// --- MONTAGEM DA SAÍDA FINAL ---

// Monta a string de horário completa, incluindo o fuso horário
const horarioDataCompleto = `${dataFormatada} da ${horarioInicio} às ${horarioFim}`;

// Monta a mensagem de saída final no formato desejado
const output = `
Horário e Data: ${horarioDataCompleto}

Link da Call: ${linkCall}

Assunto: ${assunto}
`;

// Retorna o JSON com a mensagem final pronta
return [{ json: { output } }];

const results = [];

for (const item of items) {
  try {
    // Verifica se os valores existem
    if (!item.json.horario_ocupado_start || !item.json.horario_ocupado_end) {
      throw new Error("Horário não disponível");
    }

    // Pegando os valores do JSON
    const startDateTime = item.json.horario_ocupado_start; // Exemplo: "2025-06-03T08:35:00-03:00"
    const endDateTime = item.json.horario_ocupado_end;
    const eventId = item.json.id_evento_calendar || "ID não disponível";
    const eventStatus = item.json.id_evento_calendar_status || "Status não disponível";

    // Extraindo e-mails dos participantes (converte string JSON para objeto, se necessário)
    const emailAttendList = typeof item.json.email_attend === "string" 
      ? JSON.parse(item.json.email_attend) 
      : item.json.email_attend;

    // Pega o primeiro e-mail da lista, se houver
    const email = emailAttendList?.[0]?.email || "E-mail não disponível";

    // Função para formatar a data corretamente para "dd/MM/yyyy HH:mm" com fuso de São Paulo
    function formatDateTime(isoString) {
      if (!isoString) return "Data inválida"; // Caso a data seja nula ou indefinida

      const date = new Date(isoString);
      const opcoesFuso = { timeZone: "America/Sao_Paulo", hour12: false };
      const dateBrasil = new Date(date.toLocaleString("en-US", opcoesFuso));

      if (isNaN(dateBrasil.getTime())) {
        console.log("Erro ao converter data:", isoString); // Debugging
        return "Data inválida"; // Caso a conversão falhe
      }

      const day = String(dateBrasil.getDate()).padStart(2, '0');
      const month = String(dateBrasil.getMonth() + 1).padStart(2, '0'); // Mês começa do 0
      const year = dateBrasil.getFullYear();
      const hours = String(dateBrasil.getHours()).padStart(2, '0');
      const minutes = String(dateBrasil.getMinutes()).padStart(2, '0');

      return `${day}/${month}/${year} ${hours}:${minutes}`;
    }

    // Formata as datas corretamente
    const startFormatted = formatDateTime(startDateTime);
    const endFormatted = formatDateTime(endDateTime);

    // Adiciona os dados formatados ao resultado final
    results.push({
      json: {
        email: email, // Exemplo: "usuario@example.com"
        horario_agendado_inicio: startFormatted, // Exemplo: "03/06/2025 08:35"
        horario_agendado_fim: endFormatted, // Exemplo: "03/06/2025 08:35"
        id_evento: eventId, // Exemplo: "cos92fmvp9dqk9q69b5o6q48o8"
        status_evento: eventStatus // Exemplo: "confirmed"
      }
    });

  } catch (error) {
    console.log("Erro ao processar item:", error.message); // Debugging

    // Em caso de erro, retorna valores padrão
    results.push({
      json: {
        email: "E-mail não disponível",
        horario_agendado_inicio: "Data inválida",
        horario_agendado_fim: "Data inválida",
        id_evento: "ID não disponível",
        status_evento: "Status não disponível"
      }
    });
  }
}

// Retorna os dados formatados para o próximo nó no n8n
return results;

// Pegando os valores do input do n8n de forma correta
const inputData = $('DadosAgendamento').first().json;

const conversationStory = inputData.conversationStory; // Mensagem do usuário
const horario = inputData.horarioAgendamento;          // Data vinda do input
const tempoReuniaoMinutos = inputData.tempoReuniao;    // Duração da reunião em minutos

// Função "inteligente" para parsear a data, que lida com AMBOS os formatos
function parseDataBr(dataString) {
    if (!dataString || typeof dataString !== 'string') {
      // Retorna uma data inválida se a entrada for nula ou não for uma string
      return new Date(NaN);
    }

    // Variáveis que vamos preencher
    let dia, mes, ano, horas, minutos, segundos;

    // Normaliza a string, trocando 'T' por espaço, caso exista
    const dataComEspaco = dataString.replace('T', ' ');

    // Separa a string em "parte da data" e "parte da hora"
    const dataLimpa = dataComEspaco.split(' ')[0] + ' ' + dataComEspaco.split(' ')[1];
    const [datePart, timePart] = dataLimpa.split(' ');

    // ----- A TRATATIVA ESTÁ AQUI -----
    // Detecta o formato da data pelo separador
    if (datePart.includes('/')) {
      // Formato é DD/MM/YYYY
      [dia, mes, ano] = datePart.split('/').map(Number);
    } else {
      // Formato é YYYY-MM-DD
      [ano, mes, dia] = datePart.split('-').map(Number);
    }
    // --------------------------------

    // A parte da hora é igual para ambos os formatos
    [horas, minutos, segundos] = timePart.split(':').map(Number);

    // mes - 1 porque em JavaScript os meses começam em 0
    return new Date(ano, mes - 1, dia, horas, minutos, segundos || 0);
}

// Criando um objeto Date a partir da string recebida
const dataInicio = parseDataBr(horario);

// Criando uma nova data para o horário de encerramento (endDate)
const dataEncerramento = new Date(dataInicio);
dataEncerramento.setMinutes(dataEncerramento.getMinutes() + tempoReuniaoMinutos);

// Formatando as datas no formato ISO 8601
const formatarISOComFuso = (data) => {
    if (isNaN(data.getTime())) {
      return 'NaN-NaN-NaNTNaN:NaN:00-03:00';
    }
    const ano = data.getFullYear();
    const mes = String(data.getMonth() + 1).padStart(2, '0');
    const dia = String(data.getDate()).padStart(2, '0');
    const horas = String(data.getHours()).padStart(2, '0');
    const minutos = String(data.getMinutes()).padStart(2, '0');
    const segundos = "00";
    const fusoHorario = "-03:00";

    return `${ano}-${mes}-${dia}T${horas}:${minutos}:${segundos}${fusoHorario}`;
};

// Criando as strings formatadas
const startDate = formatarISOComFuso(dataInicio);
const endDate = formatarISOComFuso(dataEncerramento);

// Retornando os dados no formato esperado
return [{
    json: {
        mensagem: conversationStory,
        inicio_hora: startDate,
        final_hora: endDate
    }
}];

// --- DADOS DOS NÓS ANTERIORES ---
// Pega a lista de eventos (pode estar vazia)
const eventosOcupados = $('Normalizador').all(); 
// Pega as regras de agendamento
const regrasAgendamento = $('DadosAgendamento').first().json;

const inicioAtendimento = regrasAgendamento.inicioAtendimento; // Ex: 9
const fimAtendimento = regrasAgendamento.fimAtendimento;     // Ex: 17
const intervaloPausaMinutos = regrasAgendamento.intervalo;    // Ex: 30
const duracaoMinutos = regrasAgendamento.tempoReuniao || 60; // Usa tempoReuniao

// --- FUNÇÃO PARA FORMATAR DATAS OCUPADAS ---
// Esta é a função "inteligente" que lida com múltiplos formatos
function formatarDataOcupada(dataString) {
  if (!dataString || typeof dataString !== 'string') return null;

  let dia, mes, ano, horas, minutos, segundos;
  const dataComEspaco = dataString.replace('T', ' ');
  const [datePart, timePart] = dataComEspaco.split(' ');

  if (!datePart || !timePart) return null;

  if (datePart.includes('/')) {
    [dia, mes, ano] = datePart.split('/').map(Number);
  } else {
    [ano, mes, dia] = datePart.split('-').map(Number);
  }

  [horas, minutos, segundos] = timePart.split(':').map(Number);

  // Cria um objeto Date baseado em UTC para evitar conversão de fuso do servidor
  const date = new Date(Date.UTC(ano, mes - 1, dia, horas, minutos, segundos || 0));

  if (isNaN(date.getTime())) return null;

  // Usa os métodos getUTC* para retornar a string no formato "DD/MM/YYYY HH:mm"
  const finalDay = String(date.getUTCDate()).padStart(2, '0');
  const finalMonth = String(date.getUTCMonth() + 1).padStart(2, '0');
  const finalYear = date.getUTCFullYear();
  const finalHours = String(date.getUTCHours()).padStart(2, '0');
  const finalMinutes = String(date.getUTCMinutes()).padStart(2, '0');

  return `${finalDay}/${finalMonth}/${finalYear} ${finalHours}:${finalMinutes}`;
}

// --- LÓGICA PRINCIPAL ---

// 1. CRIA A LISTA DE HORÁRIOS OCUPADOS
const horariosOcupados = new Set();
// Verifica se a entrada de eventos não está vazia e se o primeiro evento tem data
if (eventosOcupados.length > 0 && eventosOcupados[0].json.horario_ocupado_start) {
  for (const item of eventosOcupados) {
    const horarioFormatado = formatarDataOcupada(item.json.horario_ocupado_start);
    if (horarioFormatado) {
      horariosOcupados.add(horarioFormatado);
    }
  }
}
// Se não houver eventos, 'horariosOcupados' simplesmente continuará vazio, que é o correto.

// 2. GERA OS HORÁRIOS DISPONÍVEIS (LÓGICA DO ANTIGO 'Code12')
const horariosDisponiveis = {};
const timezone = 'America/Sao_Paulo'; 
const agora = new Date(new Date().toLocaleString('en-US', { timeZone: timezone }));

for (let i = 0; i < 7; i++) {
    const dataAtualLoop = new Date(agora);
    dataAtualLoop.setDate(agora.getDate() + i);

    const diasSemana = ["Domingo", "Segunda-Feira", "Terça-Feira", "Quarta-Feira", "Quinta-Feira", "Sexta-Feira", "Sábado"];
    const diaSemanaComData = `${diasSemana[dataAtualLoop.getDay()]} (${String(dataAtualLoop.getDate()).padStart(2, '0')}/${String(dataAtualLoop.getMonth() + 1).padStart(2, '0')})`;

    if (diasSemana[dataAtualLoop.getDay()] === "Sábado" || diasSemana[dataAtualLoop.getDay()] === "Domingo") {
        continue;
    }

    const dataFormatada = `${String(dataAtualLoop.getDate()).padStart(2, '0')}/${String(dataAtualLoop.getMonth() + 1).padStart(2, '0')}/${dataAtualLoop.getFullYear()}`;
    horariosDisponiveis[diaSemanaComData] = [];

    const inicioDia = new Date(dataAtualLoop);
    inicioDia.setHours(inicioAtendimento, 0, 0, 0);
    const fimDia = new Date(dataAtualLoop);
    fimDia.setHours(fimAtendimento, 0, 0, 0);

    let horarioInicioSlot = new Date(inicioDia);

    while (horarioInicioSlot.getTime() + duracaoMinutos * 60000 <= fimDia.getTime()) {
        if (i === 0 && horarioInicioSlot < agora) {
            horarioInicioSlot.setMinutes(horarioInicioSlot.getMinutes() + duracaoMinutos + intervaloPausaMinutos);
            continue;
        }

        const horaFormatada = `${String(horarioInicioSlot.getHours()).padStart(2, '0')}:${String(horarioInicioSlot.getMinutes()).padStart(2, '0')}`;
        const chaveOcupado = `${dataFormatada} ${horaFormatada}`;

        if (!horariosOcupados.has(chaveOcupado)) {
            const horarioFimSlot = new Date(horarioInicioSlot.getTime() + duracaoMinutos * 60000);
            const horarioFimFormatado = `${String(horarioFimSlot.getHours()).padStart(2, '0')}:${String(horarioFimSlot.getMinutes()).padStart(2, '0')}`;
            horariosDisponiveis[diaSemanaComData].push(`${horaFormatada} às ${horarioFimFormatado}`);
        }

        horarioInicioSlot.setMinutes(horarioInicioSlot.getMinutes() + duracaoMinutos + intervaloPausaMinutos);
    }
}

// 3. FORMATA A SAÍDA FINAL
const resultado = [];
const diasComVagas = Object.keys(horariosDisponiveis).filter(dia => horariosDisponiveis[dia].length > 0);
const diasSelecionados = diasComVagas.slice(0, 2);

for (const dia of diasSelecionados) {
    const horarios = horariosDisponiveis[dia];
    resultado.push(`${dia}:\n- Horários disponíveis: ${horarios.join(", ")}`);
}

// 4. RETORNA O JSON PARA O N8N
return [{
    json: {
        horarios_disponiveis: resultado.join("\n\n") || "Desculpe, não encontramos horários disponíveis para os próximos dias."
    }
}];

// Pega TODOS os itens que vêm do nó anterior (ex: "Buscar Eventos")
const items = $input.all();

// --- CENÁRIO 1: NÃO HÁ AGENDAMENTOS ---
// Se o array de itens estiver vazio, significa que a busca não retornou eventos.
if (items.length === 0) {
  // Retorna a mensagem padrão e encerra a execução.
  return [{
    json: {
      output: "Não possui agendamento"
    }
  }];
}

// --- CENÁRIO 2: EXISTEM AGENDAMENTOS ---

// Array para guardar nossas mensagens formatadas
const results = [];

// Função auxiliar para formatar a data e hora, corrigindo o fuso horário
function formatarHorario(startIso, endIso) {
  // Função interna para "enganar" o JS e tratar os números da string como UTC
  function parseISOAsUTC(isoString) {
    if (!isoString) return new Date(NaN);
    // Pega apenas a parte "YYYY-MM-DDTHH:MM:SS" e adiciona 'Z' para tratar como UTC
    const cleanISO = isoString.substring(0, 19);
    return new Date(cleanISO + 'Z');
  }

  const dataInicio = parseISOAsUTC(startIso);
  const dataFim = parseISOAsUTC(endIso);

  if (isNaN(dataInicio.getTime()) || isNaN(dataFim.getTime())) {
    return "Data ou hora inválida";
  }

  const diasDaSemana = ["domingo", "segunda-feira", "terça-feira", "quarta-feira", "quinta-feira", "sexta-feira", "sábado"];

  // Usa os métodos getUTC* para pegar os valores corretos
  const diaSemana = diasDaSemana[dataInicio.getUTCDay()];
  const dia = String(dataInicio.getUTCDate()).padStart(2, '0');
  const mes = String(dataInicio.getUTCMonth() + 1).padStart(2, '0');
  const ano = dataInicio.getUTCFullYear();

  const horaInicio = String(dataInicio.getUTCHours()).padStart(2, '0');
  const minutoInicio = String(dataInicio.getUTCMinutes()).padStart(2, '0');

  const horaFim = String(dataFim.getUTCHours()).padStart(2, '0');
  const minutoFim = String(dataFim.getUTCMinutes()).padStart(2, '0');

  // Retorna a string de data e hora formatada
  return `Horário e Data: ${diaSemana}, ${dia}/${mes}/${ano} da ${horaInicio}:${minutoInicio} às ${horaFim}:${minutoFim}`;
}


// Loop para processar cada evento encontrado
for (const item of items) {
  try {
    // Pega os dados do evento atual
    const startDateTime = item.json.start?.dateTime;
    const endDateTime = item.json.end?.dateTime;
    const linkCall = item.json.hangoutLink || "Link não disponível";
    const assunto = item.json.summary || "Assunto não disponível";

    // Se não houver data/hora, pula para o próximo item
    if (!startDateTime || !endDateTime) {
      continue;
    }

    // Formata o horário usando a nossa função auxiliar
    const horarioFormatado = formatarHorario(startDateTime, endDateTime);

    // Monta a mensagem de saída final para este evento
    const outputString = `Agendamento marcado para: \n${horarioFormatado}\n\nLink da Call: ${linkCall}\n\nAssunto: ${assunto}\n`;

    // Adiciona o resultado formatado ao nosso array de saídas
    results.push({
      json: {
        output: outputString
      }
    });

  } catch (error) {
    // Caso algum evento seja mal-formado, registra o erro e continua
    console.log("Erro ao processar um evento:", error.message);
  }
}

// Retorna todos os agendamentos formatados. 
// Se o loop não processar nada, o array 'results' estará vazio e o n8n não passará nada para frente.
return results;
